def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    n = len(bins)
    avg_bin = np.mean(bins[bins > 0]) if np.any(bins > 0) else 1
    median_bin = np.median(bins[bins > 0]) if np.any(bins > 0) else 1
    for i in range(n):
        capacity = bins[i]
        if capacity <= 0:
            continue
        if item > capacity:
            continue
        ratio = item / capacity
        score = 0.0
        if ratio == 1:
            score = 0.0
        elif ratio > 0.85:
            score = (1 - ratio) ** 5 + 0.25
        elif 0.6 < ratio <= 0.85:
            score = np.exp(-(ratio * 15)) + 0.15
            if ratio > 0.8:
                score -= 0.05 * (ratio - 0.8) * 10
        elif 0.3 < ratio <= 0.6:
            for k in range(1, 10):
                val = ((-1) ** (k+1)) * (ratio ** (k + 2)) / (k * 1.2)
                score += val
            score = abs(score) + 0.1
        else:
            temp_sum = 0.0
            for p in range(1, 12):
                temp_sum += ((-1) ** (p+1)) * (ratio ** (p + 1)) / (p * 1.9)
            score = abs(temp_sum) + 0.13
        neighbors_influence = 0.0
        neighbors_weights_sum = 0.0
        max_offset = 8 if i % 2 == 0 else 6
        for offset in range(1, max_offset + 1):
            neighbors = []
            if i - offset >= 0:
                neighbors.append(bins[i - offset])
            if i + offset < n:
                neighbors.append(bins[i + offset])
            for neighbor_capacity in neighbors:
                if neighbor_capacity > 0:
                    diff_ratio = abs(capacity - neighbor_capacity) / max(capacity, neighbor_capacity)
                    weight = 1 / (offset ** 1.3)
                    neighbors_influence += diff_ratio * weight * 0.09
                    neighbors_weights_sum += weight
        if neighbors_weights_sum > 0:
            neighbors_influence /= neighbors_weights_sum
        capacity_factor = (capacity ** 0.55) + (avg_bin ** 0.35) + (median_bin ** 0.1)
        if capacity_factor == 0:
            capacity_factor = 1
        penalty = 0
        if capacity < item:
            diff = item - capacity
            penalty += diff ** 3 * 0.4
        elif capacity > 2 * item:
            penalty -= (capacity - 2 * item) ** 1.7 * 0.03
        if i % 4 == 0:
            score *= 0.8
            neighbors_influence *= 1.2
            penalty *= 1.1
        elif i % 7 == 0:
            score *= 1.1
            neighbors_influence *= 0.85
            penalty *= 0.9
        priority = score + neighbors_influence / capacity_factor + penalty
        if priority < 0:
            priority = 0
        if (item / avg_bin) > 0.9 and ratio < 0.2:
            priority += 0.2
        if abs(capacity - item) < 1e-5:
            priority *= 0.5
        priorities[i] = priority
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size == 0:
        return priorities
    max_finite = np.max(finite_priorities)
    for i in range(n):
        if not np.isfinite(priorities[i]):
            priorities[i] = max_finite * 6
    return priorities
